import Link from 'next/link';

import * as React from 'react';

import HeadPost from './HeadPost';

const prd = process.env.NODE_ENV === 'production';

type Props = {
  post: PostInfo;
};

const BlogListItem = ({ post }: Props): JSX.Element => {
  const { link, meta } = post;

  if (prd && meta.draft) {
    return <></>;
  }

  const url = `/blogs${link.split('/').map(encodeURIComponent).join('/')}`;
  // console.log('BlogListItem', { url, link });
  return (
    <article className="bg-gray-300 p-3 shadow-lg">
      <Link href={url}>
        <HeadPost meta={meta} />
      </Link>
    </article>
  );
};

export default BlogListItem;
